"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { 
  Sparkles, 
  Flame, 
  Heart, 
  Gamepad2, 
  Coffee, 
  Rocket 
} from "lucide-react";

// Define the structure for our stickers
interface Sticker {
  id: number;
  icon: React.ReactNode;
  color: string;
  borderColor: string;
  // Custom scatter physics per sticker
  targetX: number;  // Random X coordinate on scatter (vw)
  targetY: number;  // Random Y coordinate on scatter (vh)
  rotate: number;   // Scatter rotation
}

const stickerData: Sticker[] = [
  { 
    id: 1, 
    icon: <Rocket className="w-8 h-8 text-indigo-500 fill-indigo-100" />, 
    color: "bg-indigo-50", 
    borderColor: "border-indigo-200",
    targetX: -250, targetY: -180, rotate: -25 
  },
  { 
    id: 2, 
    icon: <Flame className="w-8 h-8 text-orange-500 fill-orange-100" />, 
    color: "bg-orange-50", 
    borderColor: "border-orange-200",
    targetX: 280, targetY: -150, rotate: 15 
  },
  { 
    id: 3, 
    icon: <Heart className="w-8 h-8 text-rose-500 fill-rose-100" />, 
    color: "bg-rose-50", 
    borderColor: "border-rose-200",
    targetX: -300, targetY: 120, rotate: -15 
  },
  { 
    id: 4, 
    icon: <Gamepad2 className="w-8 h-8 text-emerald-500 fill-emerald-100" />, 
    color: "bg-emerald-50", 
    borderColor: "border-emerald-200",
    targetX: 250, targetY: 160, rotate: 30 
  },
  { 
    id: 5, 
    icon: <Coffee className="w-8 h-8 text-amber-600 fill-amber-100" />, 
    color: "bg-amber-50", 
    borderColor: "border-amber-200",
    targetX: -80, targetY: -220, rotate: 8 
  },
  { 
    id: 6, 
    icon: <Sparkles className="w-8 h-8 text-purple-500 fill-purple-100" />, 
    color: "bg-purple-50", 
    borderColor: "border-purple-200",
    targetX: 120, targetY: 230, rotate: -20 
  },
];

export default function StickerCard() {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <div className="relative flex items-center justify-center min-h-[600px] w-full overflow-visible">

      {/* --- STICKERS LAYER (Behind the card) --- */}
      <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
        <AnimatePresence>
          {stickerData.map((sticker) => (
            <motion.div
              key={sticker.id}
              className={`absolute p-3 rounded-2xl border-4 ${sticker.borderColor} ${sticker.color} 
                         shadow-[0_10px_20px_rgba(0,0,0,0.15),_inset_0_-4px_0_rgba(0,0,0,0.1)] 
                         flex items-center justify-center cursor-grab active:cursor-grabbing`}
              style={{
                // Add a cool die-cut sticker peel effect using CSS radial gradients/shadows
                boxShadow: "0 10px 25px -5px rgba(0, 0, 0, 0.3), 0 8px 10px -6px rgba(0, 0, 0, 0.3), inset 0 -3px 0 0 rgba(0,0,0,0.1)",
              }}
              initial={{ x: 0, y: 0, scale: 0.2, rotate: 0, opacity: 0 }}
              animate={
                isHovered
                  ? {
                      x: sticker.targetX,
                      y: sticker.targetY,
                      scale: 1.1,
                      rotate: sticker.rotate,
                      opacity: 1,
                      transition: {
                        type: "spring",
                        stiffness: 120,
                        damping: 12, // Lower damping = more bouncy "pop" effect
                        mass: 0.8,
                      },
                    }
                  : {
                      x: 0,
                      y: 0,
                      scale: 0.2,
                      rotate: 0,
                      opacity: 0,
                      transition: {
                        type: "spring",
                        stiffness: 200,
                        damping: 25,
                      },
                    }
              }
              whileHover={{ 
                scale: 1.25, 
                rotate: sticker.rotate + 10,
                zIndex: 50,
                transition: { duration: 0.2 } 
              }}
            >
              {/* Sticker Page Curl Accent (Skeuomorphic Detail) */}
              <div className="absolute top-0 right-0 w-3 h-3 bg-white/40 rounded-bl-md border-b border-l border-black/5" />
              {sticker.icon}
            </motion.div>
          ))}
        </AnimatePresence>
      </div>

      {/* --- THE MAIN CARD --- */}
      <motion.div
        className="relative z-10 w-80 h-96 rounded-3xl bg-white/80 backdrop-blur-md border border-white/20 
                   shadow-[0_20px_50px_rgba(0,0,0,0.1)] flex flex-col justify-between p-6 cursor-pointer"
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
        whileHover={{ 
          y: -8,
          scale: 1.02,
          boxShadow: "0 30px 60px rgba(0,0,0,0.15)"
        }}
        transition={{ type: "spring", stiffness: 300, damping: 20 }}
      >
        {/* Card Header */}
        <div className="flex justify-between items-center">
          <span className="text-xs font-bold tracking-widest text-gray-400 uppercase">
            Interactive Toy
          </span>
          <div className="w-2.5 h-2.5 rounded-full bg-emerald-400 animate-ping" />
        </div>

        {/* Card Content */}
        <div className="my-auto space-y-3">
          <h2 className="text-3xl font-extrabold text-slate-800 tracking-tight leading-none">
            Hover to <br />
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-purple-600 to-indigo-600">
              Unleash
            </span>
          </h2>
          <p className="text-sm text-slate-500 font-medium">
            Hover over this card to scatter premium physics-based stickers all over your view viewport.
          </p>
        </div>

        {/* Card Footer */}
        <div className="pt-4 border-t border-slate-100 flex items-center justify-between">
          <span className="text-xs font-semibold text-slate-600">Framer Motion Active</span>
          <Sparkles className="w-4 h-4 text-purple-500 animate-pulse" />
        </div>
      </motion.div>

    </div>
  );
}
